class Session {
public:
    Session(int id, std::string data) : id(id), data(data), expirationTime(std::chrono::steady_clock::now() + std::chrono::minutes(30)) {}

    int getId() const { return id; }
    std::string getData() const { return data; }
    bool isExpired() const { return std::chrono::steady_clock::now() > expirationTime; }

private:
    int id;
    std::string data;
    std::chrono::time_point<std::chrono::steady_clock> expirationTime;
};

class CachingSystem {
public:
    Session* createSession(int id, std::string data) {
        sessions[id] = new Session(id, data);
        return sessions[id];
    }

    void accessSession(int id) {
        if (sessions.find(id) != sessions.end() && !sessions[id]->isExpired()) {
            // Do something with the session
            std::cout << "Accessing session ID: " << id << ", Data: " << sessions[id]->getData() << std::endl;
        } else {
            std::cout << "Session ID: " << id << " not found or expired." << std::endl;
        }
    }

    void invalidateSession(int id) {
        if (sessions.find(id) != sessions.end()) {
            delete sessions[id];
            sessions.erase(id);
        }
    }

private:
    std::unordered_map<int, Session*> sessions;
};

